INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('lightweight', '軽量な（少ないリソースで動作する）', 'adjective', '言語仕様', 'MDN JavaScript トップページ', 'JavaScript (JS) is a lightweight interpreted programming language.', 'JavaScript（JS）は軽量なインタプリタ型プログラミング言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('interpreted', 'インタプリタ型の（コードを1行ずつ実行する方式）', 'adjective', '実行環境', 'MDN JavaScript トップページ', 'JavaScript is a lightweight interpreted (or just-in-time compiled) programming language.', 'JavaScriptは軽量なインタプリタ型（またはJITコンパイル型）のプログラミング言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('just-in-time compiled', 'JITコンパイルされる（実行時にコンパイルする方式）', 'compound adjective', '実行環境', 'MDN JavaScript トップページ', 'JavaScript is a lightweight interpreted (or just-in-time compiled) programming language.', 'JavaScriptは軽量なインタプリタ型（またはJITコンパイル型）のプログラミング言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('first-class functions', '第一級関数（関数を変数に代入したり引数に渡したりできること）', 'noun phrase', '言語仕様', 'MDN JavaScript トップページ', '...a programming language with first-class functions.', '...第一級関数を備えたプログラミング言語。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('well-known', 'よく知られた', 'compound adjective', '一般', 'MDN JavaScript トップページ', 'It is most well-known as the scripting language for Web pages.', 'Webページのスクリプト言語として最もよく知られている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('non-browser environments', 'ブラウザ以外の環境（"non-" は否定の接頭辞）', 'noun phrase', '実行環境', 'MDN JavaScript トップページ', 'Many non-browser environments also use it.', '多くのブラウザ以外の環境でも使われている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('prototype-based', 'プロトタイプベースの（クラスではなくプロトタイプチェーンで継承を実現する方式）', 'compound adjective', '言語仕様', 'MDN JavaScript トップページ', 'JavaScript is a prototype-based, garbage-collected, dynamic language.', 'JavaScriptはプロトタイプベースの、ガベージコレクション付きの動的言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('garbage-collected', 'ガベージコレクション付きの（不要なメモリを自動回収する仕組み）', 'compound adjective', '実行環境', 'MDN JavaScript トップページ', 'JavaScript is a prototype-based, garbage-collected, dynamic language.', 'JavaScriptはプロトタイプベースの、ガベージコレクション付きの動的言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('dynamic', '動的な（型が実行時に決まる言語の特性。⇔ static）', 'adjective', '言語仕様', 'MDN JavaScript トップページ', 'JavaScript is a prototype-based, garbage-collected, dynamic language.', 'JavaScriptはプロトタイプベースの、ガベージコレクション付きの動的言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('paradigm', 'パラダイム（プログラミングの考え方・手法）', 'noun', '言語仕様', 'MDN JavaScript トップページ', '...supporting multiple paradigms such as imperative, functional, and object-oriented.', '命令型、関数型、オブジェクト指向など複数のパラダイムをサポートしている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('imperative', '命令型の（手順を順番に記述するプログラミングスタイル。⇔ declarative）', 'adjective', '言語仕様', 'MDN JavaScript トップページ', '...supporting multiple paradigms such as imperative, functional, and object-oriented.', '命令型、関数型、オブジェクト指向など複数のパラダイムをサポートしている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('functional', '関数型の（関数を第一級オブジェクトとして扱うプログラミングスタイル）', 'adjective', '言語仕様', 'MDN JavaScript トップページ', '...supporting multiple paradigms such as imperative, functional, and object-oriented.', '命令型、関数型、オブジェクト指向など複数のパラダイムをサポートしている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('object-oriented', 'オブジェクト指向の（OOP。クラスやオブジェクトで構造化する手法）', 'compound adjective', '言語仕様', 'MDN JavaScript トップページ', '...supporting multiple paradigms such as imperative, functional, and object-oriented.', '命令型、関数型、オブジェクト指向など複数のパラダイムをサポートしている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('extension', '拡張機能（エディタやブラウザに追加する機能）', 'noun', '開発ツール', 'Anthropic Docs - Claude Code VS Code', 'Install and configure the Claude Code extension for VS Code.', 'VS Code用のClaude Code拡張機能をインストールして設定する。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('inline diff', 'インライン差分（コード変更をエディタ内で直接表示する形式）', 'noun phrase', '開発ツール', 'Anthropic Docs - Claude Code VS Code', 'Get AI coding assistance with inline diffs, @-mentions, plan review, and keyboard shortcuts.', 'インライン差分、@メンション、プランレビュー、キーボードショートカット付きのAIコーディング支援を得る。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('native', 'ネイティブの（組み込みの、外部ツールでなく直接統合された）', 'adjective', '一般', 'Anthropic Docs - Claude Code VS Code', 'The VS Code extension provides a native graphical interface for Claude Code.', 'VS Code拡張機能はClaude Codeのネイティブなグラフィカルインターフェースを提供する。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('integrated', '統合された（直接組み込まれた）', 'adjective', '一般', 'Anthropic Docs - Claude Code VS Code', '...a native graphical interface, integrated directly into your IDE.', 'IDEに直接統合されたネイティブのグラフィカルインターフェース。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('recommended', '推奨される（おすすめの）', 'adjective', '一般', 'Anthropic Docs - Claude Code VS Code', 'This is the recommended way to use Claude Code in VS Code.', 'これはVS CodeでClaude Codeを使う推奨される方法である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('conversation history', '会話履歴（チャットやAIとのやり取りの記録）', 'noun phrase', 'AI・LLM', 'Anthropic Docs - Claude Code VS Code', '...access conversation history, and open multiple conversations in separate tabs.', '会話履歴にアクセスし、別々のタブで複数の会話を開く。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('X is a ... with ...', '「Xは〜を備えた...である」技術の定義パターン', 'sentence pattern', '一般', 'MDN JavaScript トップページ', 'JavaScript is a lightweight interpreted programming language with first-class functions.', 'JavaScriptは第一級関数を備えた軽量なインタプリタ型プログラミング言語である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('While ..., ... also ...', '「〜として知られているが、〜でもある」対比表現', 'sentence pattern', '一般', 'MDN JavaScript トップページ', 'While it is most well-known as the scripting language, many non-browser environments also use it.', 'スクリプト言語として最もよく知られているが、ブラウザ以外の多くの環境でも使われている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('such as A, B and C', '「例えばA、B、Cなど」具体例の列挙', 'phrase', '一般', 'MDN JavaScript トップページ', '...many non-browser environments also use it, such as Node.js, Apache CouchDB and Adobe Acrobat.', '...ブラウザ以外の多くの環境でも使われている。例えば Node.js、Apache CouchDB、そして Adobe Acrobat など。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('X is a ..., supporting ...', '「Xは〜であり、〜をサポートしている」分詞構文で情報を追加するパターン', 'sentence pattern', '一般', 'MDN JavaScript トップページ', 'JavaScript is a ... dynamic language, supporting multiple paradigms.', 'JavaScriptは動的言語であり、複数のパラダイムをサポートしている。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('the recommended way to ...', '「〜するための推奨される方法」ベストプラクティスを示す定番表現', 'sentence pattern', '一般', 'Anthropic Docs - Claude Code VS Code', 'This is the recommended way to use Claude Code in VS Code.', 'これはVS CodeでClaude Codeを使う推奨される方法である。', 2, 0);
INSERT INTO words (word, meaning_general, part_of_speech, domain, source, example_en, example_ja, level, known) VALUES ('Install and configure ...', '「〜をインストールして設定する」導入手順の命令文パターン', 'sentence pattern', '一般', 'Anthropic Docs - Claude Code VS Code', 'Install and configure the Claude Code extension for VS Code.', 'VS Code用のClaude Code拡張機能をインストールして設定する。', 2, 0);
